const i = $input.first() ? ($input.first().json || {}) : {};
function pick(){ for(var k=0;k<arguments.length;k++){ var v=arguments[k]; if(v!=null && String(v).trim()!=='') return String(v).trim(); } return ''; }
let custom = pick(i['Custom topic']); let drop = pick(i['Topic'], i.topic); if(/^custom/i.test(drop)) drop='';
let t = pick(custom, drop, i.query, i.text); t = t.replace(/^\/[a-zA-Z]+\b/, '').trim();
if(!t) t = ($env.DEFAULT_AWARENESS_TOPIC || 'phishing');
let len = parseInt(pick(i['Length (seconds)'], i['Length'], i.length), 10); if(isNaN(len)) len = 90;
return [{ json: { topic:t, audience:(pick(i['Audience'],i.audience)||'All staff'), length:len, date:new Date().toISOString().slice(0,10), client:($env.CLIENT_NAME||'').toString(), outDir:'video', filePrefix:'storyboard', fileSafe:(t.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').slice(0,40)||'video') } }];

