const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text;
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const r = $('Resolve Input').first().json || {};
return [{ json: Object.assign({}, r, { data: data }) }];

const r = $json || {};
const d = r.data || {};
const topic = r.topic || 'Security Awareness';
const client = (r.client || '').toString();
const brand = client ? client : 'Security Awareness';
const length = r.length || 90;
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function arr(x){ return Array.isArray(x)?x:(x==null||x===''?[]:[x]); }
const title = d.title || (topic + ' — Awareness Video');
const scenes = arr(d.scenes);
const CSS = "@page{size:A4;margin:14mm} *{box-sizing:border-box} body{margin:0;font-family:-apple-system,'Segoe UI',Arial,sans-serif;color:#14202b} "
+".hd{border-bottom:3px solid #0E7C86;padding-bottom:10px;margin-bottom:14px} .hd .k{color:#0E7C86;letter-spacing:3px;font-size:12px;font-weight:800;text-transform:uppercase} "
+".hd h1{margin:4px 0 0;font-size:25px;color:#0E2233} .hd .s{color:#5A6472;font-size:13px;margin-top:4px} "
+".hook{background:#F1F7F8;border-left:4px solid #0E7C86;border-radius:6px;padding:12px 16px;margin:0 0 16px;font-size:15px;font-style:italic;color:#0E2233} "
+".sc{display:flex;gap:14px;border:1px solid #e2e6ec;border-radius:8px;padding:12px 14px;margin:0 0 12px;page-break-inside:avoid} "
+".sc .frame{flex:0 0 150px;height:90px;background:linear-gradient(135deg,#0E2233,#0E7C86);border-radius:6px;color:#fff;display:flex;align-items:flex-end;padding:8px;font-size:11px;line-height:1.3} "
+".sc .body{flex:1} .sc .n{font-weight:800;color:#0E7C86;font-size:12px} .sc .vo{font-size:14px;line-height:1.5;color:#2b3340;margin:4px 0} "
+".sc .os{display:inline-block;background:#0E2233;color:#fff;border-radius:4px;padding:3px 8px;font-size:11px;margin-top:4px} .sc .t{float:right;color:#8a98a4;font-size:11px} "
+".cta{margin-top:8px;background:#0E2233;color:#fff;border-radius:8px;padding:14px 16px;font-size:15px;font-weight:700} "
+".foot{margin-top:14px;border-top:1px solid #e2e6ec;padding-top:8px;color:#8a98a4;font-size:10px;display:flex;justify-content:space-between}";
let cards = scenes.map(function(s,k){
  return '<div class="sc"><div class="frame">'+esc(s.visual||('Scene '+(k+1)))+'</div><div class="body">'
    +'<div class="n">SCENE '+(k+1)+(s.seconds?'<span class="t">~'+esc(s.seconds)+'s</span>':'')+'</div>'
    +'<div class="vo"><b>VO:</b> '+esc(s.voiceover||'')+'</div>'
    +(s.onScreen?'<span class="os">'+esc(s.onScreen)+'</span>':'')+'</div></div>';
}).join('');
const html = '<!doctype html><html><head><meta charset="utf-8"><style>'+CSS+'</style></head><body>'
+'<div class="hd"><div class="k">Video Script &amp; Storyboard</div><h1>'+esc(title)+'</h1>'
+'<div class="s">'+esc(brand)+' · Audience: '+esc(r.audience||'All staff')+' · Target length: '+length+'s · '+scenes.length+' scenes</div></div>'
+(d.hook?'<div class="hook">“'+esc(d.hook)+'”</div>':'')
+cards
+(d.cta?'<div class="cta">Call to action: '+esc(d.cta)+'</div>':'')
+'<div class="foot"><span>'+esc(brand)+' · AI-generated script — review before production</span><span>'+esc(r.date)+'</span></div></body></html>';
return [{ json: { html: html, topic: topic, date: r.date, fileSafe: r.fileSafe, outDir: 'video', filePrefix: 'storyboard' } }];

const html = $json.html || '';
return [{ json: { topic:$json.topic, date:$json.date, fileSafe:$json.fileSafe, outDir:$json.outDir, filePrefix:$json.filePrefix },
  binary: { data: { data: Buffer.from(html,'utf8').toString('base64'), mimeType:'text/html', fileName:'index.html' } } }];

const fs = require('fs');
const meta = $('Render HTML').first().json;
const dir = '/reports/awareness/' + (meta.outDir || 'misc');
const name = (meta.filePrefix || 'asset') + '-' + (meta.fileSafe || 'item') + '-' + meta.date + '.pdf';
let buf = null;
try { buf = await this.helpers.getBinaryDataBuffer(0, 'data'); } catch (e) {}
try { fs.mkdirSync(dir, { recursive: true }); if (buf) fs.writeFileSync(dir + '/' + name, buf); } catch (e) {}
const out = { json: { ok: !!buf, file: dir + '/' + name, topic: meta.topic } };
try { const b = $input.first().binary; if (b && b.data) { b.data.fileName = name; out.binary = { data: b.data }; } } catch (e) {}
return [out];
